+
+      // Open
+      await act(async () => {
+        fireEvent.click(button);
+      });
+      expect(button).toHaveAttribute("aria-expanded", "true");
+
+      // Press escape
+      await act(async () => {
+        fireEvent.keyDown(document, { key: "Escape" });
